import React, { useState, useEffect } from 'react'
import axios from 'axios';
import { Layout } from 'antd';
import store from '../../Redux/store'
import { useNavigate } from 'react-router-dom'
import { useFriendList } from '../Layout/index'
const { Content, Sider } = Layout;

const userId = localStorage.getItem('userId')

export default function Contacts() {
  const [isClick, setIsClick] = useState(false);
  const [isClickSearch, setIsClickSearch] = useState(false);
  const [query, setQuery] = useState('');
  const [searchResult, setSearchResult] = useState([]);
  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  const [firendList, setFriendList] = useState(store.getState().contactReducer.user);
  const [isLoadingContacts, setIsLoadingContacts] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const navigate = useNavigate();
  const { friendList_room, setFriendList_room } = useFriendList()

  useEffect(() => {
    LoadContactList()
  }, [])

  const handleAddFriends = () => {
    setIsClick(!isClick);
  }

  const handleEnterKey = (event) => {
    if (event.key === 'Enter') {
      SearchUser();
      setIsClickSearch(!isClickSearch);
    }
  }

  // 搜索好友
  const SearchUser = async () => {
    setSuccessMessage('');
    setErrorMessage('');
    try {
      const response = await axios.get(`http://localhost:4000/api/search?query=${query}`);
      setSearchResult(response.data);
    } catch (error) {
      console.error('搜索失败：', error)
    }
  }

  // 添加好友
  const AddFriends = async (friendId) => {
    try {
      const response = await axios.post('http://localhost:4000/api/addFriends',
        {
          userIdToAdd: friendId,
          currentUserId: userId
        });
      console.log(friendId, userId);
      const message = response.data.message;
      console.log(message);
      setSuccessMessage(message);
      LoadContactList();
    } catch (error) {
      setErrorMessage(`${error.message}`)
      console.error('添加好友失败', error);
    }
  }

  const LoadContactList = () => {
    setIsLoadingContacts(true);

    try {
      if (store.getState().contactReducer.user.length === 0) {
        // 如果联系人列表为空，才触发加载操作
        store.dispatch(getContactListAction());
        store.subscribe(() => {
          setFriendList(store.getState().contactReducer.user)
        })
      }
    } catch (error) {
      console.error('加载联系人列表时出错：', error);
    } finally {
      setIsLoadingContacts(false);
    }
  };

  const hanleChatButtonClick = async () => {
    try {
      const userId1 = userId;
      const userId2 = selectedUser.username;

      const response = await axios.post('http://localhost:4000/api/createRoom', {
        userId1,
        userId2
      });

      if (response.status === 200) {
        const roomId = response.data.roomId;
        if (!friendList_room.includes(selectedUser.username)) {
          setFriendList_room((prevFriendList) => [...prevFriendList, selectedUser.username]);
        }
        navigate(`/room/chat?selectedUser=${userId2}&roomId=${roomId}`);
      }
    } catch (error) {
      console.error('发生错误：', error);
    }
  }

  const UserDetails = ({ user }) => {
    if (!user) {
      return null;
    }
    return (
      <div style={{
        margin: '10px',
        textAlign: 'center'
      }}>
        <h1 style={{
          margin: '50px'
        }}>{user.username}</h1>
        <Button variant="outlined" size="medium" onClick={hanleChatButtonClick}>
          Chat
        </Button>
      </div>
    )
  }

  return (
    <Content
      style={{
        padding: '0 50px',
        margin: "30px"
      }}
    >
      <Layout
        style={{
          height: "100%",
          padding: '24px 0',
          backgroundColor: "rgb(100,100,100,0.6)",
        }}
      >
        <Sider
          width={200}
          style={{
            backgroundColor: "transparent"
          }}
        >

        </Sider>
        <Content
          style={{
            padding: '0 24px',
            minHeight: 280,
          }}
        >
          Contacts
        </Content>
      </Layout>
    </Content>
  )
}
